function isValidIpv4Address(value = "") {
  const text = String(value || "").trim();
  if (!text || !/^(?:\d{1,3}\.){3}\d{1,3}$/.test(text)) return false;
  const parts = text.split(".");
  return parts.length === 4 && parts.every(part => {
    const num = Number(part);
    return Number.isInteger(num) && num >= 0 && num <= 255;
  });
}

function isValidIpv6Address(value = "") {
  const text = String(value || "").trim();
  if (!text || !text.includes(":") || /\s/.test(text)) return false;
  try {
    new URL(`http://[${text}]/`);
    return true;
  } catch {
    return false;
  }
}

function normalizeIpType(value = "") {
  if (String(value || "").trim().toUpperCase() === "IPV6") return "IPv6";
  return "IPv4";
}

function detectIpType(value = "") {
  if (isValidIpv6Address(value)) return "IPv6";
  return isValidIpv4Address(value) ? "IPv4" : "";
}

function extractIpListFromText(value = "") {
  const text = String(value || "");
  const seen = new Set();
  const items = [];
  const pushIp = (ip) => {
    const normalizedIp = String(ip || "").trim();
    if (!normalizedIp) return;
    const type = detectIpType(normalizedIp);
    if (!type) return;
    const key = normalizedIp.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    items.push({ ip: normalizedIp, ipType: type });
  };
  for (const match of text.match(IPV4_REGEX) || []) pushIp(match);
  for (const match of text.match(IPV6_CANDIDATE_REGEX) || []) pushIp(match);
  return items;
}

function normalizeCfColoMeta(code = "") {
  const normalizedCode = String(code || "").trim().toUpperCase();
  const meta = CF_COLO_META[normalizedCode];
  if (!normalizedCode) {
    return {
      coloCode: "",
      cityName: "",
      countryCode: "UNKNOWN",
      countryName: "未知"
    };
  }
  if (!meta) {
    return {
      coloCode: normalizedCode,
      cityName: normalizedCode,
      countryCode: "UNKNOWN",
      countryName: "未知"
    };
  }
  return {
    coloCode: normalizedCode,
    cityName: String(meta.cityName || normalizedCode),
    countryCode: String(meta.countryCode || "UNKNOWN"),
    countryName: String(meta.countryName || "未知")
  };
}

function extractColoCodeFromCfRay(value = "") {
  const text = String(value || "").trim();
  if (!text) return "";
  const matched = text.match(/-([A-Za-z]{3,4})$/);
  return matched ? String(matched[1] || "").trim().toUpperCase() : "";
}

function getCorsHeadersForResponse(env, request, originOverride = null) {
  const reqOrigin = request.headers.get("Origin");
  const reqHeaders = request.headers.get("Access-Control-Request-Headers") || corsHeaders["Access-Control-Allow-Headers"];
  const allowOrigin = originOverride || reqOrigin || corsHeaders["Access-Control-Allow-Origin"];
  return {
    "Access-Control-Allow-Origin": allowOrigin,
    "Access-Control-Allow-Methods": corsHeaders["Access-Control-Allow-Methods"],
    "Access-Control-Allow-Headers": reqHeaders,
    "Access-Control-Expose-Headers": "Content-Length, Content-Range, X-Emby-Auth-Token, X-MediaBrowser-Auth-Token",
    "Access-Control-Max-Age": "86400"
  };
}

function safeDecodeSegment(segment = "") {
  if (!segment) return "";
  try { return decodeURIComponent(segment); } catch { return segment; }
}

function sanitizeProxyPath(path) {
  let raw = typeof path === "string" ? path : "/";
  if (!raw) return "/";
  if (!raw.startsWith("/")) raw = "/" + raw;
  raw = raw.replace(/^\/+/, "/");
  return raw;
}

function normalizeAdminPath(value) {
  const fallback = "/admin";
  const raw = String(value || "").trim();
  if (!raw) return fallback;
  let normalized = sanitizeProxyPath(raw);
  normalized = normalized.replace(/\/{2,}/g, "/");
  if (normalized.length > 1) normalized = normalized.replace(/\/+$/, "");
  if (!normalized || normalized === "/" || normalized.toLowerCase().startsWith("/api")) return fallback;
  return normalized;
}

function pathnameMatchesPrefix(pathname, prefix) {
  const safePath = sanitizeProxyPath(pathname || "/");
  const safePrefix = sanitizeProxyPath(prefix || "/");
  return safePath === safePrefix || safePath.startsWith(safePrefix + "/");
}

function getAdminPath(env) {
  return normalizeAdminPath(env?.ADMIN_PATH);
}

function getAdminLoginPath(env) {
  const adminPath = getAdminPath(env);
  return adminPath === "/" ? "/login" : `${adminPath}/login`;
}

function getAdminCookiePath(env) {
  const adminPath = getAdminPath(env);
  return adminPath === "/" ? "/" : adminPath;
}

function escapeHtml(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function serializeInlineJson(value) {
  return JSON.stringify(value)
    .replace(/</g, "\\u003c")
    .replace(/>/g, "\\u003e")
    .replace(/&/g, "\\u0026")
    .replace(/\u2028/g, "\\u2028")
    .replace(/\u2029/g, "\\u2029");
}

function buildInitHealth(env) {
  const missing = [];
  if (!env?.JWT_SECRET) missing.push("JWT_SECRET");
  if (!env?.ADMIN_PASS) missing.push("ADMIN_PASS");
  const adminPath = getAdminPath(env);
  const loginPath = getAdminLoginPath(env);
  return {
    ok: missing.length === 0,
    missing,
    adminPath,
    loginPath,
    message: missing.length
      ? `系统未初始化：缺少 ${missing.join("、")}。`
      : "系统初始化检查通过。"
  };
}

function warnInitHealthOnce(env) {
  const health = buildInitHealth(env);
  if (health.ok) return health;
  const fingerprint = health.missing.join("|") || "unknown";
  if (!GLOBALS.InitCheckWarnedFingerprints.has(fingerprint)) {
    GLOBALS.InitCheckWarnedFingerprints.add(fingerprint);
    console.warn(`[Init Check] ${health.message} 管理入口: ${health.adminPath}`);
  }
  return health;
}

function buildInitHealthBannerHtml(initHealth) {
  if (!initHealth || initHealth.ok) return "";
  const missingText = Array.isArray(initHealth.missing) && initHealth.missing.length
    ? initHealth.missing.map(item => `<code class="rounded bg-amber-100/80 px-1.5 py-0.5 text-[11px] font-semibold text-amber-700">${escapeHtml(item)}</code>`).join(" ")
    : `<code class="rounded bg-amber-100/80 px-1.5 py-0.5 text-[11px] font-semibold text-amber-700">UNKNOWN</code>`;
  return `<div id="init-health-banner" class="mx-4 mt-4 rounded-2xl border border-amber-200 bg-amber-50/95 px-4 py-3 text-sm text-amber-900 shadow-sm">
    <div class="flex flex-col gap-1 md:flex-row md:items-center md:justify-between">
      <div class="font-semibold">系统未初始化</div>
      <div class="text-xs text-amber-700">管理入口：${escapeHtml(initHealth.adminPath || "/admin")}</div>
    </div>
    <p class="mt-2 leading-6">检测到关键环境变量缺失：${missingText}</p>
    <p class="mt-1 text-xs leading-5 text-amber-700">请先在 Cloudflare Worker 环境变量中补齐后再使用管理台登录与敏感操作。</p>
  </div>`;
}

function escapeSqlLike(value) {
  return String(value || "").replace(/[\\%_]/g, "\\$&");
}

function isLikelyIpAddress(value) {
  const text = String(value || "").trim();
  if (!text) return false;
  if (/^(?:\d{1,3}\.){3}\d{1,3}$/.test(text)) return true;
  return /^[0-9a-f:]+$/i.test(text) && text.includes(":");
}

function isLikelyColoCode(value) {
  const text = String(value || "").trim();
  if (!text) return false;
  return /^[a-z]{3,4}$/i.test(text);
}

function resolveRequestColoCode(request) {
  const text = String(request?.cf?.colo || "").trim().toUpperCase();
  return text || "UNKNOWN";
}

function normalizeTargetBasePath(pathname = "/") {
  const safePath = sanitizeProxyPath(pathname || "/");
  if (safePath === "/") return "";
  return safePath.replace(/\/+$/, "");
}

function normalizeNodeMediaAuthMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "inherit") return "inherit";
  if (normalized === "emby") return "emby";
  if (normalized === "jellyfin") return "jellyfin";
  if (normalized === "passthrough") return "passthrough";
  return "auto";
}

function normalizeNodeRealClientIpMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "inherit") return "inherit";
  if (normalized === "forward") return "forward";
  if (normalized === "strip") return "strip";
  if (normalized === "disable" || normalized === "none") return "disable";
  return "forward";
}

function normalizeDefaultMediaAuthMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "emby") return "emby";
  if (normalized === "jellyfin") return "jellyfin";
  if (normalized === "passthrough") return "passthrough";
  return "auto";
}

function normalizeDefaultRealClientIpMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "strip") return "strip";
  if (normalized === "disable" || normalized === "none") return "disable";
  return "forward";
}

function normalizeScheduleUtcOffsetMinutes(value) {
  return clampIntegerConfig(value, Config.Defaults.ScheduleUtcOffsetMinutes, -12 * 60, 14 * 60);
}

function normalizeScheduleClockTime(value = "", fallback = "00:00") {
  const fallbackText = String(fallback || "00:00").trim() || "00:00";
  const text = String(value || "").trim();
  const matched = text.match(/^(\d{1,2}):(\d{1,2})$/);
  if (!matched) return fallbackText;
  const hour = Number(matched[1]);
  const minute = Number(matched[2]);
  if (!Number.isInteger(hour) || hour < 0 || hour > 23) return fallbackText;
  if (!Number.isInteger(minute) || minute < 0 || minute > 59) return fallbackText;
  return `${String(hour).padStart(2, "0")}:${String(minute).padStart(2, "0")}`;
}

function normalizeDnsAutoUploadCountryCodes(value = []) {
  const rawValues = Array.isArray(value)
    ? value
    : String(value || "").split(",");
  const allowedCodes = new Set(Object.values(CF_COLO_META).map(meta => String(meta?.countryCode || "").trim().toUpperCase()).filter(Boolean));
  return [...new Set(rawValues
    .map(item => String(item || "").trim().toUpperCase())
    .filter(code => code && allowedCodes.has(code)))];
}

function normalizeDnsAutoUploadRecordTypes(value = []) {
  const rawValues = Array.isArray(value)
    ? value
    : [value];
  const normalized = [...new Set(rawValues
    .map(item => String(item || "").trim().toUpperCase())
    .filter(type => type === "A" || type === "AAAA"))];
  return normalized.length ? normalized : ["A"];
}

function normalizeDnsIpSourceIpLimit(value) {
  return clampIntegerConfig(value, Config.Defaults.DnsIpSourceIpLimit, 1, 1000);
}

function normalizeNodeMainVideoStreamMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "direct") return "direct";
  if (normalized === "proxy") return "proxy";
  return "inherit";
}

function readNodeMainVideoStreamMode(node = {}) {
  return normalizeNodeMainVideoStreamMode(node?.mainVideoStreamMode ?? node?.wangpanDirectMode ?? node?.wangpanMode);
}

const NODE_LEGACY_DIRECT_MODE_KEYS = ["proxyMode", "mode"];
const NODE_LEGACY_DIRECT_BOOLEAN_KEYS = ["direct", "sourceDirect", "directSource", "direct2xx"];
const NODE_LEGACY_METADATA_KEYS = ["wangpanMode", "videoThrottling", "interceptMs"];
const NODE_LEGACY_FIELD_KEYS = [
  ...NODE_LEGACY_DIRECT_MODE_KEYS,
  ...NODE_LEGACY_DIRECT_BOOLEAN_KEYS,
  ...NODE_LEGACY_METADATA_KEYS
];

function collectLegacyNodeState(node = {}) {
  const rawNode = node && typeof node === "object" && !Array.isArray(node) ? node : {};
  const legacyKeysPresent = [];
  let shouldAddToSourceDirectNodes = false;

  for (const key of NODE_LEGACY_DIRECT_MODE_KEYS) {
    if (!Object.prototype.hasOwnProperty.call(rawNode, key)) continue;
    legacyKeysPresent.push(key);
    const normalizedMode = String(rawNode[key] || "").trim().toLowerCase();
    if (["direct", "source-direct", "origin-direct", "node-direct"].includes(normalizedMode)) {
      shouldAddToSourceDirectNodes = true;
    }
  }

  for (const key of NODE_LEGACY_DIRECT_BOOLEAN_KEYS) {
    if (!Object.prototype.hasOwnProperty.call(rawNode, key)) continue;
    legacyKeysPresent.push(key);
    if (rawNode[key] === true) shouldAddToSourceDirectNodes = true;
  }

  for (const key of NODE_LEGACY_METADATA_KEYS) {
    if (!Object.prototype.hasOwnProperty.call(rawNode, key)) continue;
    legacyKeysPresent.push(key);
  }

  return {
    legacyKeysPresent: normalizeDistinctConfigKeyList(legacyKeysPresent),
    shouldAddToSourceDirectNodes
  };
}

function resolveNodeVideoStreamPolicy(node, currentConfig = {}) {
  const mode = readNodeMainVideoStreamMode(node);
  return {
    mode,
    forceVideoDirect: mode === "direct",
    forceVideoProxy: mode === "proxy"
  };
}

function resolveDefaultNodeMediaAuthMode(currentConfig = {}) {
  return normalizeDefaultMediaAuthMode(currentConfig?.defaultMediaAuthMode);
}

function resolveDefaultNodeRealClientIpMode(currentConfig = {}) {
  return normalizeDefaultRealClientIpMode(currentConfig?.defaultRealClientIpMode);
}

function resolveEffectiveNodeMediaAuthMode(node = {}, currentConfig = {}) {
  const typedNode = /** @type {{ mediaAuthMode?: string }} */ (node || {});
  const hasNodeMode = !!node && typeof node === "object" && Object.prototype.hasOwnProperty.call(node, "mediaAuthMode");
  const nodeMode = hasNodeMode
    ? normalizeNodeMediaAuthMode(typedNode.mediaAuthMode)
    : "auto";
  return nodeMode === "inherit" ? resolveDefaultNodeMediaAuthMode(currentConfig) : nodeMode;
}

function resolveEffectiveNodeRealClientIpMode(node = {}, currentConfig = {}) {
  const typedNode = /** @type {{ realClientIpMode?: string }} */ (node || {});
  const hasNodeMode = !!node && typeof node === "object" && Object.prototype.hasOwnProperty.call(node, "realClientIpMode");
  const nodeMode = hasNodeMode
    ? normalizeNodeRealClientIpMode(typedNode.realClientIpMode)
    : "forward";
  return nodeMode === "inherit" ? resolveDefaultNodeRealClientIpMode(currentConfig) : nodeMode;
}

function getRealClientIpHeaderMode(modeOrNode) {
  const rawMode = typeof modeOrNode === "string"
    ? modeOrNode
    : modeOrNode?.realClientIpMode;
  const nodeMode = normalizeDefaultRealClientIpMode(rawMode);
  if (nodeMode === "forward") return "full";
  if (nodeMode === "strip") return "real-ip-only";
  if (nodeMode === "disable") return "none";
  return "full";
}

// 保留节点 target 自带的子路径，避免 /node/foo 被错误拼到源站根目录。
function buildUpstreamProxyUrl(targetBase, proxyPath = "/") {
  const baseUrl = targetBase instanceof URL ? new URL(targetBase.toString()) : new URL(String(targetBase || ""));
  const basePath = normalizeTargetBasePath(baseUrl.pathname);
  const safeProxyPath = sanitizeProxyPath(proxyPath);
  const resolvedPath = safeProxyPath === "/"
    ? (basePath ? `${basePath}/` : "/")
    : `${basePath}${safeProxyPath}`;
  baseUrl.pathname = resolvedPath || "/";
  baseUrl.search = "";
  baseUrl.hash = "";
  return baseUrl;
}

function translateUpstreamUrlToProxyLocation(upstreamUrl, activeTargetBase, name, key) {
  try {
    const resolvedUrl = upstreamUrl instanceof URL ? upstreamUrl : new URL(String(upstreamUrl || ""));
    const targetBase = activeTargetBase instanceof URL ? activeTargetBase : new URL(String(activeTargetBase || ""));
    if (resolvedUrl.origin !== targetBase.origin) return resolvedUrl.toString();
    const basePath = normalizeTargetBasePath(targetBase.pathname);
    let proxyPath = resolvedUrl.pathname || "/";
    if (basePath) {
      if (proxyPath === basePath || proxyPath === `${basePath}/`) proxyPath = "/";
      else if (proxyPath.startsWith(`${basePath}/`)) proxyPath = proxyPath.slice(basePath.length);
      else return resolvedUrl.toString();
    }
    proxyPath = sanitizeProxyPath(proxyPath);
    return `${buildProxyPrefix(name, key)}${proxyPath === "/" ? "/" : proxyPath}${resolvedUrl.search}${resolvedUrl.hash}`;
  } catch {
    return null;
  }
}

function sanitizeSyntheticRedirectHeaders(headers) {
  [
    "Age",
    "Accept-Ranges",
    "Content-Disposition",
    "Content-Encoding",
    "Content-Language",
    "Content-Length",
    "Content-Location",
    "Content-Range",
    "Content-Type",
    "ETag",
    "Expires",
    "Last-Modified",
    "Set-Cookie",
    "Transfer-Encoding"
  ].forEach(header => headers.delete(header));
}

function buildProxyPrefix(name, key) {
  const encodedName = encodeURIComponent(String(name || ""));
  if (!key) return "/" + encodedName;
  return "/" + encodedName + "/" + encodeURIComponent(String(key));
}

function normalizePrewarmDepth(value) {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  return normalized === "poster_manifest" ? "poster_manifest" : "poster";
}

function normalizeLogSearchMode(value) {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "fts") return "fts";
  if (normalized === "like") return "like";
  return Config.Defaults.LogSearchMode;
}

function normalizeLogRequestGroupFilter(value) {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "playback" || normalized === "playback_info") return "playback_info";
  if (normalized === "image") return "image";
  if (normalized === "api") return "api";
  if (normalized === "auth") return "auth";
  return "";
}

function normalizeLogDeliveryModeFilter(value) {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "direct") return "direct";
  if (normalized === "proxy" || normalized === "proxied") return "proxy";
  return "";
}

function normalizeProtocolFailureReason(value = "") {
  const normalized = String(value || "").trim().toLowerCase().replace(/[\s-]+/g, "_");
  if (normalized === "connect_timeout") return "connect_timeout";
  if (normalized === "idle_timeout") return "idle_timeout";
  if (normalized === "tls_handshake_failed") return "tls_handshake_failed";
  if (normalized === "http_version_fallback") return "http_version_fallback";
  if (normalized === "redirect_loop") return "redirect_loop";
  if (normalized === "redirect_limit_exceeded") return "redirect_limit_exceeded";
  if (normalized === "range_unsatisfied") return "range_unsatisfied";
  if (normalized === "upstream_4xx") return "upstream_4xx";
  if (normalized === "upstream_5xx") return "upstream_5xx";
  if (normalized === "unknown_fetch_error") return "unknown_fetch_error";
  return "";
}

function looksLikeFtsExpression(value) {
  const text = String(value || "").trim();
  if (!text) return false;
  if (/\b(?:AND|OR|NOT|NEAR)\b/i.test(text)) return true;
  if (/(?:^|\s)(?:node_name|request_path|user_agent|error_detail)\s*:/i.test(text)) return true;
  if (/(?:^|\s)[^\s"]+\*/.test(text)) return true;
  return /^"(?:[^"]|"")+"$/.test(text);
}

function quoteFtsTerm(term) {
  return `"${String(term || "").replace(/"/g, '""')}"`;
}

function quoteFtsPrefixTerm(term) {
  return `${quoteFtsTerm(term)}*`;
}

function normalizeFtsExpression(text) {
  return String(text || "").replace(
    /(^|\s)((?:node_name|request_path|user_agent|error_detail)\s*:\s*)([^"\s()]+)(?=\s|$)/gi,
    (match, lead, prefix, value) => `${lead}${prefix}${quoteFtsTerm(value)}`
  );
}

function buildFtsMatchQuery(value) {
  const text = String(value || "").trim();
  if (!text) return "";
  if (looksLikeFtsExpression(text)) return normalizeFtsExpression(text);
  return text
    .split(/\s+/)
    .filter(Boolean)
    .map(token => quoteFtsPrefixTerm(token))
    .join(" AND ");
}

function normalizeLogPageCursor(value = null) {
  if (!value || typeof value !== "object") return null;
  const timestamp = Math.floor(Number(value.timestamp));
  const id = Math.floor(Number(value.id));
  if (!Number.isFinite(timestamp) || !Number.isFinite(id) || timestamp < 0 || id < 0) return null;
  return { timestamp, id };
}

function buildLogPageCursorFromRow(row = null) {
  return normalizeLogPageCursor({
    timestamp: Number(row?.timestamp),
    id: Number(row?.id)
  });
}

function normalizeRegionCodeCsv(value = "") {
  return [...new Set(
    String(value || "")
      .split(",")
      .map(item => item.trim().toUpperCase())
      .filter(Boolean)
  )].join(",");
}

function quoteSqlIdentifier(name) {
  return `"${String(name || "").replace(/"/g, '""')}"`;
}

function normalizeSqlIdentifierSearchText(sql) {
  return String(sql || "")
    .toLowerCase()
    .replace(/["`\[\]]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function parseContentLengthHeader(value) {
  const raw = String(value || "").trim();
  if (!/^\d+$/.test(raw)) return null;
  const parsed = Number(raw);
  return Number.isFinite(parsed) ? parsed : null;
}

function getDefaultCacheHandle() {
  try {
    /** @type {unknown} */
    const globalObject = globalThis;
    /** @type {WorkerGlobalWithCachesLike | null | undefined} */
    const runtimeGlobals = globalObject;
    return runtimeGlobals?.caches?.default ?? null;
  } catch {
    return null;
  }
}

const WORKER_CACHE_DROP_QUERY_PARAMS = new Set([
  "apikey",
  "accesstoken",
  "token",
  "authorization",
  "xembytoken",
  "xembyauthorization",
  "xmediabrowsertoken",
  "xmediabrowserauthorization",
  "deviceid",
  "xembydeviceid",
  "xembydevicename",
  "xembyclient",
  "xembyclientversion",
  "xmediabrowserdeviceid",
  "xmediabrowserdevicename",
  "xmediabrowserclient",
  "xmediabrowserclientversion",
  "client",
  "clientid",
  "devicename",
  "userid",
  "playsessionid",
  "sessionid"
]);
const WORKER_METADATA_MANIFEST_ALLOWED_PATHS = [
  /^\/Videos\/[^/]+\/(?:main|master|stream)\.m3u8$/i,
  /^\/Videos\/[^/]+\/(?:manifest|main|master|stream)\.mpd$/i,
  /^\/Audio\/[^/]+\/(?:main|master|stream)\.m3u8$/i
];
const WORKER_METADATA_MANIFEST_ALLOWED_PARAMS = new Set([
  "mediasourceid",
  "static",
  "tag",
  "audiostreamindex",
  "subtitlestreamindex",
  "subtitlemethod",
  "starttimeticks"
]);

function normalizeWorkerCacheParamName(name = "") {
  return String(name || "").trim().toLowerCase().replace(/[^a-z0-9]+/g, "");
}

function shouldStripWorkerCacheQueryParam(name = "") {
  return WORKER_CACHE_DROP_QUERY_PARAMS.has(normalizeWorkerCacheParamName(name));
}

function normalizeWorkerCacheUrl(url) {
  const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
  normalizedUrl.hash = "";
  const keptParams = [];
  for (const [key, value] of normalizedUrl.searchParams.entries()) {
    if (shouldStripWorkerCacheQueryParam(key)) continue;
    keptParams.push([key, value]);
  }
  keptParams.sort((a, b) => {
    const keyDiff = a[0].localeCompare(b[0]);
    if (keyDiff !== 0) return keyDiff;
    return String(a[1]).localeCompare(String(b[1]));
  });
  normalizedUrl.search = "";
  for (const [key, value] of keptParams) normalizedUrl.searchParams.append(key, value);
  return normalizedUrl;
}

function normalizeMetadataCachePath(pathname = "") {
  const rawPath = String(pathname || "");
  const match = /\/(?:Videos|Audio)\/.+$/i.exec(rawPath);
  return match ? match[0] : rawPath;
}

function buildWorkerCacheKey(url) {
  try {
    return new Request(normalizeWorkerCacheUrl(url).toString(), { method: "GET" });
  } catch {
    return null;
  }
}

function isTranscodingManifestUrl(url) {
  try {
    const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
    for (const [key, value] of normalizedUrl.searchParams.entries()) {
      const lowerKey = String(key || "").toLowerCase();
      const lowerValue = String(value || "").toLowerCase();
      if (lowerKey.includes("transcod") || lowerValue.includes("transcod")) return true;
    }
    return false;
  } catch {
    return true;
  }
}

function isWhitelistedMetadataManifestUrl(url) {
  try {
    const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
    const normalizedPath = normalizeMetadataCachePath(normalizedUrl.pathname || "");
    if (!GLOBALS.Regex.ManifestExt.test(normalizedPath)) return false;
    if (isTranscodingManifestUrl(normalizedUrl)) return false;
    if (!WORKER_METADATA_MANIFEST_ALLOWED_PATHS.some(rule => rule.test(normalizedPath))) return false;
    for (const [key] of normalizedUrl.searchParams.entries()) {
      if (shouldStripWorkerCacheQueryParam(key)) continue;
      if (!WORKER_METADATA_MANIFEST_ALLOWED_PARAMS.has(normalizeWorkerCacheParamName(key))) return false;
    }
    return true;
  } catch {
    return false;
  }
}

function shouldWorkerCacheMetadataUrl(url) {
  try {
    const normalizedUrl = url instanceof URL ? new URL(url.toString()) : new URL(String(url || ""));
    const pathname = normalizedUrl.pathname || "";
    if (GLOBALS.Regex.EmbyImages.test(pathname) || GLOBALS.Regex.ImageExt.test(pathname)) return true;
    if (GLOBALS.Regex.SubtitleExt.test(pathname)) return true;
    if (GLOBALS.Regex.ManifestExt.test(pathname)) return isWhitelistedMetadataManifestUrl(normalizedUrl);
    return false;
  } catch {
    return false;
  }
}

function isHeavyVideoBytePath(pathname = "") {
  const lowerPath = String(pathname || "").toLowerCase();
  if (!lowerPath) return false;
  if (/\.(?:mp4|m4v|mkv|mov|avi|wmv|flv|ts|m4s)(?:$|[?#])/.test(lowerPath)) return true;
  if (GLOBALS.Regex.ManifestExt.test(lowerPath) || GLOBALS.Regex.SubtitleExt.test(lowerPath)) return false;
  return /\/videos\/[^/]+\/(?:stream|original|download|file)\b/.test(lowerPath) || /\/items\/[^/]+\/download\b/.test(lowerPath);
}

function collectMetadataUrlStrings(input, collector = new Set(), depth = 0) {
  if (input === null || input === undefined || depth > 5) return collector;
  if (typeof input === "string") {
    const value = input.trim();
    if (value && /^(?:https?:\/\/|\/)/i.test(value)) {
      const lowerValue = value.toLowerCase();
      const matchTarget = lowerValue.split(/[?#]/, 1)[0] || lowerValue;
      if (
        GLOBALS.Regex.ManifestExt.test(matchTarget) ||
        GLOBALS.Regex.SubtitleExt.test(matchTarget) ||
        GLOBALS.Regex.EmbyImages.test(lowerValue) ||
        GLOBALS.Regex.ImageExt.test(matchTarget)
      ) {
        collector.add(value);
      }
    }
    return collector;
  }
  if (Array.isArray(input)) {
    input.slice(0, 24).forEach(item => collectMetadataUrlStrings(item, collector, depth + 1));
    return collector;
  }
  if (typeof input === "object") {
    Object.values(input).slice(0, 32).forEach(value => collectMetadataUrlStrings(value, collector, depth + 1));
  }
  return collector;
}

function extractProxyItemId(proxyPath = "") {
  const match = /^\/Items\/([^/]+)(?:\/|$)/i.exec(String(proxyPath || ""));
  return match ? safeDecodeSegment(match[1]) : "";
}

function rankMetadataWarmPath(pathname = "") {
  const lowerPath = String(pathname || "").toLowerCase();
  if (GLOBALS.Regex.EmbyImages.test(lowerPath) || GLOBALS.Regex.ImageExt.test(lowerPath)) return 0;
  if (GLOBALS.Regex.ManifestExt.test(lowerPath)) return 1;
  if (GLOBALS.Regex.SubtitleExt.test(lowerPath)) return 2;
  return 3;
}

function normalizeNodeNameList(input) {
  const rawList = Array.isArray(input)
    ? input
    : String(input || "").split(/[\\r\\n,，;；|]+/);
  const seen = new Set();
  const result = [];
  for (const item of rawList) {
    const value = String(item || "").trim();
    if (!value) continue;
    const key = value.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    result.push(value);
  }
  return result;
}

function hashStableText(input = "") {
  const text = String(input || "");
  let hash = 2166136261;
  for (let i = 0; i < text.length; i += 1) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(36);
}

function createDnsIpPoolSourceId(seed = "") {
  return `dns-ip-source-${hashStableText(seed || `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`)}`;
}

function normalizeDnsIpPoolItemRecord(item = {}, options = {}) {
  const rawIp = String(item?.ip || item?.content || "").trim();
  const ipType = detectIpType(rawIp);
  if (!rawIp || !ipType) return null;
  const nowIso = String(options.updatedAt || new Date().toISOString());
  const sourceKind = String(item?.sourceKind || item?.source_kind || options.sourceKind || "manual").trim().toLowerCase() || "manual";
  const sourceLabel = String(item?.sourceLabel || item?.source_label || options.sourceLabel || "").trim();
  const remark = String(item?.remark || "").trim();
  return {
    id: String(item?.id || `dns-ip-${hashStableText(rawIp.toLowerCase())}`),
    ip: rawIp,
    ipType,
    sourceKind,
    sourceLabel,
    remark,
    createdAt: String(item?.createdAt || item?.created_at || options.createdAt || nowIso),
    updatedAt: nowIso
  };
}

function normalizeDnsIpPoolSourceRecord(source = {}, index = 0) {
  const nowIso = new Date().toISOString();
  const name = String(source?.name || "").trim();
  const url = String(source?.url || "").trim();
  return {
    id: String(source?.id || createDnsIpPoolSourceId(`${name}|${url}|${index}`)),
    name: name || `抓取源 ${Number(index) + 1}`,
    url,
    enabled: source?.enabled !== false,
    sortOrder: Math.max(0, Number.parseInt(String(source?.sortOrder ?? source?.sort_order ?? index), 10) || 0),
    ipLimit: normalizeDnsIpSourceIpLimit(source?.ipLimit ?? source?.ip_limit),
    lastFetchAt: String(source?.lastFetchAt || source?.last_fetch_at || ""),
    lastFetchStatus: String(source?.lastFetchStatus || source?.last_fetch_status || ""),
    lastFetchCount: Math.max(0, Number(source?.lastFetchCount ?? source?.last_fetch_count) || 0),
    createdAt: String(source?.createdAt || source?.created_at || nowIso),
    updatedAt: String(source?.updatedAt || source?.updated_at || nowIso)
  };
}

function normalizeDnsIpProbeStatus(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "ok") return "ok";
  if (normalized === "cf_header_missing") return "cf_header_missing";
  if (normalized === "non_cloudflare") return "non_cloudflare";
  if (normalized === "timeout") return "timeout";
  if (normalized === "network_error") return "network_error";
  return "network_error";
}

function summarizeDnsIpWorkspaceItems(items = []) {
  const rows = Array.isArray(items) ? items : [];
  const countrySet = new Set();
  const coloSet = new Set();
  let ipv4Count = 0;
  let ipv6Count = 0;
  for (const item of rows) {
    const type = normalizeIpType(item?.ipType || item?.ip_type || item?.type || "");
    if (type === "IPv6") ipv6Count += 1;
    else ipv4Count += 1;
    const countryCode = String(item?.countryCode || item?.country_code || "").trim().toUpperCase();
    const coloCode = String(item?.coloCode || item?.colo_code || "").trim().toUpperCase();
    if (countryCode) countrySet.add(countryCode);
    if (coloCode) coloSet.add(coloCode);
  }
  return {
    ipCount: rows.length,
    ipv4Count,
    ipv6Count,
    countryCount: countrySet.size,
    coloCount: coloSet.size
  };
}

function buildDnsIpWorkspaceSummary(currentHostItems = [], sharedPoolItems = []) {
  const currentHost = summarizeDnsIpWorkspaceItems(currentHostItems);
  const sharedPool = summarizeDnsIpWorkspaceItems(sharedPoolItems);
  return {
    currentHost,
    sharedPool,
    combined: summarizeDnsIpWorkspaceItems([...(Array.isArray(currentHostItems) ? currentHostItems : []), ...(Array.isArray(sharedPoolItems) ? sharedPoolItems : [])])
  };
}

function reconcileNamedNodeSelection(currentSelection = [], options = {}) {
  const renameMapInput = options.renameMap instanceof Map
    ? options.renameMap
    : new Map(Object.entries(options.renameMap && typeof options.renameMap === "object" ? options.renameMap : {}));
  const renameMap = new Map();
  for (const [fromName, toName] of renameMapInput.entries()) {
    const fromKey = String(fromName || "").trim().toLowerCase();
    const nextName = String(toName || "").trim();
    if (!fromKey || !nextName) continue;
    renameMap.set(fromKey, nextName);
  }
  const removedKeys = new Set(normalizeNodeNameList(options.removedNames || []).map(name => String(name || "").trim().toLowerCase()).filter(Boolean));
  /** @type {[string, string][] | null} */
  const allowedNameEntries = options.allowedNames === undefined
    ? null
    : normalizeNodeNameList(options.allowedNames || [])
        .map(name => {
          /** @type {[string, string]} */
          const entry = [String(name || "").trim().toLowerCase(), String(name || "").trim()];
          return entry;
        })
        .filter(([key, value]) => key && value);
  const allowedNameMap = allowedNameEntries ? new Map(allowedNameEntries) : null;
  const nextSelection = [];
  const seen = new Set();
  for (const rawName of normalizeNodeNameList(currentSelection)) {
    const currentKey = String(rawName || "").trim().toLowerCase();
    if (!currentKey || removedKeys.has(currentKey)) continue;
    const renamedName = renameMap.get(currentKey) || String(rawName || "").trim();
    const nextKey = renamedName.toLowerCase();
    if (!nextKey || removedKeys.has(nextKey)) continue;
    if (allowedNameMap && !allowedNameMap.has(nextKey)) continue;
    if (seen.has(nextKey)) continue;
    seen.add(nextKey);
    nextSelection.push(allowedNameMap?.get(nextKey) || renamedName);
  }
  return nextSelection;
}

function isNodeDirectSourceEnabled(node, currentConfig = null, nodeNameHint = "") {
  const proxyMode = String(node?.proxyMode || node?.mode || "").trim().toLowerCase();
  if (["direct", "source-direct", "origin-direct", "node-direct"].includes(proxyMode)) return true;
  if (node?.direct === true || node?.sourceDirect === true || node?.directSource === true || node?.direct2xx === true) return true;
  const explicitText = `${node?.tag || ""} ${node?.remark || ""}`;
  return /(?:^|[\s\[(【])(?:直连|source-direct|origin-direct|node-direct)(?:$|[\s\])】])/i.test(explicitText);
}

function isNodeVideoStreamDirectEnabled(node, currentConfig = null, nodeNameHint = "") {
  const mode = readNodeMainVideoStreamMode(node);
  if (mode === "direct") return true;
  if (mode === "proxy") return false;
  return isNodeDirectSourceEnabled(node, currentConfig, nodeNameHint);
}

function resolveRedirectTarget(location, baseUrl) {
  if (!location) return null;
  try {
    return new URL(location, baseUrl instanceof URL ? baseUrl : String(baseUrl || ""));
  } catch {
    return null;
  }
}

function normalizeRedirectMethod(status, method = "GET") {
  const upperMethod = String(method || "GET").toUpperCase();
  if (status === 303 && upperMethod !== "GET" && upperMethod !== "HEAD") return "GET";
  if ((status === 301 || status === 302) && upperMethod === "POST") return "GET";
  return upperMethod;
}

function normalizeRoutingDecisionMode(value = "") {
  return String(value || "").trim().toLowerCase() === "simplified" ? "simplified" : "legacy";
}

function normalizeProtocolStrategy(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "balanced") return "balanced";
  if (normalized === "aggressive") return "aggressive";
  return "compat";
}

function resolveProtocolStrategyFromLegacyConfig(config = {}) {
  const enableH2 = config?.enableH2 === true;
  const enableH3 = config?.enableH3 === true;
  if (!enableH2 && !enableH3) return "compat";
  return config?.peakDowngrade === false ? "aggressive" : "balanced";
}

function resolveProtocolRuntimeProfile(config = {}, options = {}) {
  const strategy = normalizeProtocolStrategy(
    hasOwnConfigKey(config, "protocolStrategy")
      ? config?.protocolStrategy
      : resolveProtocolStrategyFromLegacyConfig(config)
  );
  const hourUtc8 = Number.isFinite(Number(options.hourUtc8))
    ? Number(options.hourUtc8)
    : ((new Date().getUTCHours() + 8) % 24);
  const isPeakHour = hourUtc8 >= 20 && hourUtc8 < 24;
  if (strategy === "aggressive") {
    return {
      strategy,
      enableH2: true,
      enableH3: true,
      peakDowngrade: false,
      forceH1: false,
      isPeakHour
    };
  }
  if (strategy === "balanced") {
    return {
      strategy,
      enableH2: true,
      enableH3: true,
      peakDowngrade: true,
      forceH1: isPeakHour,
      isPeakHour
    };
  }
  return {
    strategy: "compat",
    enableH2: false,
    enableH3: false,
    peakDowngrade: true,
    forceH1: true,
    isPeakHour
  };
}

function isPlaybackInfoPath(proxyPath = "") {
  return /\/playbackinfo(?:$|[/?])/i.test(String(proxyPath || ""));
}

function isPlaybackCriticalProxyPath(proxyPath = "") {
  const normalizedPath = sanitizeProxyPath(proxyPath);
  if (isPlaybackInfoPath(normalizedPath)) return true;
  if (GLOBALS.Regex.ManifestExt.test(normalizedPath) || GLOBALS.Regex.SegmentExt.test(normalizedPath)) return true;
  return /\/videos\/[^/]+\/(?:stream|original|download|file)\b/i.test(normalizedPath)
    || /\/items\/[^/]+\/download\b/i.test(normalizedPath);
}

function isPlaybackSessionProgressPath(proxyPath = "") {
  return /\/sessions\/playing\/progress(?:$|[/?])/i.test(String(proxyPath || ""));
}

function isPlaybackSessionStoppedPath(proxyPath = "") {
  return /\/sessions\/playing\/stopped(?:$|[/?])/i.test(String(proxyPath || ""));
}

function isPlaybackSessionStartedPath(proxyPath = "") {
  const text = String(proxyPath || "");
  if (isPlaybackSessionProgressPath(text) || isPlaybackSessionStoppedPath(text)) return false;
  return /\/sessions\/playing(?:\/started)?(?:$|[/?])/i.test(text);
}

function decodeBufferedBodyText(buffer) {
  if (buffer === null || buffer === undefined) return "";
  try {
    if (buffer instanceof ArrayBuffer) return new TextDecoder().decode(new Uint8Array(buffer));
    if (ArrayBuffer.isView(buffer)) return new TextDecoder().decode(buffer);
    return String(buffer || "");
  } catch {
    return "";
  }
}

function normalizeCaseInsensitiveObject(input = {}) {
  const normalized = {};
  if (!input || typeof input !== "object" || Array.isArray(input)) return normalized;
  for (const [key, value] of Object.entries(input)) {
    const normalizedKey = String(key || "").trim().toLowerCase();
    if (!normalizedKey || normalized[normalizedKey] !== undefined) continue;
    normalized[normalizedKey] = value;
  }
  return normalized;
}

function getCaseInsensitivePayloadValue(payload = {}, names = []) {
  const normalizedPayload = normalizeCaseInsensitiveObject(payload);
  for (const name of Array.isArray(names) ? names : [names]) {
    const key = String(name || "").trim().toLowerCase();
    if (!key) continue;
    const value = normalizedPayload[key];
    if (value === undefined || value === null || value === "") continue;
    return value;
  }
  return "";
}

function hasOwnConfigKey(config = {}, key = "") {
  return !!config && typeof config === "object" && Object.prototype.hasOwnProperty.call(config, key);
}

function resolveRoutingDecisionMode(config = {}) {
  if (!config || typeof config !== "object") return "legacy";
  return normalizeRoutingDecisionMode(Reflect.get(config, "routingDecisionMode"));
}

function normalizeNodeRoutingDecisionMode(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  if (normalized === "legacy" || normalized === "simplified") return normalized;
  return "inherit";
}

function resolveEffectiveRoutingDecisionMode(node = {}, currentConfig = {}) {
  const nodeMode = normalizeNodeRoutingDecisionMode(node?.routingDecisionMode);
  return nodeMode === "inherit" ? resolveRoutingDecisionMode(currentConfig) : nodeMode;
}

const CF_DASH_CACHE_VERSION = 6;

function makeCfDashCacheKey(zoneId, dateKey = "") {
  const safeZoneId = encodeURIComponent(String(zoneId || "default").trim() || "default");
  const safeDateKey = encodeURIComponent(String(dateKey || "current").trim() || "current");
  return `sys:cf_dash_cache:${safeZoneId}:${safeDateKey}`;
}

function getVideoRequestWhereClause(column = "request_path") {
  return `(${column} LIKE '%/stream%' OR ${column} LIKE '%/master.m3u8%' OR ${column} LIKE '%/videos/%/original%' OR ${column} LIKE '%/videos/%/download%' OR ${column} LIKE '%/videos/%/file%' OR ${column} LIKE '%/items/%/download%' OR ${column} LIKE '%Static=true%' OR ${column} LIKE '%Download=true%')`;
}

function parseHostnameCandidate(rawHostname) {
  const host = String(rawHostname || "").trim().toLowerCase();
  if (!host) return null;
  const wildcard = host.includes("*");
  const cleaned = host.replace(/^\*\./, "").replace(/^\*+/, "").replace(/\*+$/g, "").replace(/^\.+|\.+$/g, "");
  if (!cleaned) return null;
  return { hostname: cleaned, wildcard };
}

function normalizeHostnameText(rawHostname) {
  return parseHostnameCandidate(rawHostname)?.hostname || "";
}

function isHostnameInsideZone(rawHostname, rawZoneName) {
  const hostname = normalizeHostnameText(rawHostname);
  const zoneName = normalizeHostnameText(rawZoneName);
  if (!hostname || !zoneName) return false;
  return hostname === zoneName || hostname.endsWith(`.${zoneName}`);
}

function extractRouteHostnameInfo(pattern) {
  const rawPattern = String(pattern || "").trim();
  if (!rawPattern) return null;
  const slashIndex = rawPattern.indexOf("/");
  const rawHost = slashIndex === -1 ? rawPattern : rawPattern.slice(0, slashIndex);
  const path = slashIndex === -1 ? "" : rawPattern.slice(slashIndex);
  const parsed = parseHostnameCandidate(rawHost);
  if (!parsed) return null;
  return { ...parsed, path, pattern: rawPattern };
}

function scoreHostnameCandidate(hostname, options = {}) {
  const path = String(options.path || "");
  let score = 0;
  if (!options.wildcard) score += 100;
  if (hostname.includes(".workers.dev")) score -= 20;
  if (path === "/" || path === "/*") score += 20;
  else if (path.endsWith("*")) score += 10;
  else if (path) score += 4;
  score += hostname.split(".").length * 4;
  score -= Math.min(path.length, 30);
  return score;
}

async function fetchCloudflareApiJson(url, apiToken, init = {}) {
  const normalizedInit = init && typeof init === "object" ? init : {};
  /** @type {any} */
  const extraInit = normalizedInit;
  let extraHeaders = {};
  const rawHeaders = extraInit?.headers;
  if (rawHeaders) {
    if (rawHeaders instanceof Headers) extraHeaders = Object.fromEntries(rawHeaders.entries());
    else if (typeof rawHeaders === "object") extraHeaders = rawHeaders;
  }
  const res = await fetch(url, {
    ...extraInit,
    headers: { "Authorization": `Bearer ${apiToken}`, "Content-Type": "application/json", ...extraHeaders }
  });
  if (!res.ok) throw new Error(`cf_api_http_${res.status}`);
  /** @type {JsonApiEnvelope} */
  const payload = await res.json();
  if (payload?.success === false) {
    const msg = Array.isArray(payload?.errors) ? payload.errors.map(item => item?.message).filter(Boolean).join("; ") : "";
    throw new Error(msg || "cf_api_error");
  }
  return payload;
}

async function fetchCloudflareGraphQL(apiToken, query, variables) {
  const body = variables && typeof variables === "object"
    ? { query, variables }
    : { query };
  const cfRes = await fetch("https://api.cloudflare.com/client/v4/graphql", {
    method: "POST",
    headers: { "Authorization": `Bearer ${apiToken}`, "Content-Type": "application/json" },
    body: JSON.stringify(body)
  });
  if (!cfRes.ok) throw new Error(`cf_graphql_http_${cfRes.status}`);
  /** @type {JsonApiEnvelope} */
  const cfData = await cfRes.json();
  if (Array.isArray(cfData?.errors) && cfData.errors.length) {
    throw new Error(cfData.errors.map(item => item?.message).filter(Boolean).join("; ") || "cf_graphql_error");
  }
  return cfData;
}

async function fetchCloudflareGraphQLZone(zoneId, apiToken, query, variables) {
  const cfData = await fetchCloudflareGraphQL(apiToken, query, variables);
  return cfData?.data?.viewer?.zones?.[0] || null;
}

async function fetchCloudflareGraphQLAccount(accountId, apiToken, query, variables) {
  const cfData = await fetchCloudflareGraphQL(apiToken, query, variables);
  return cfData?.data?.viewer?.accounts?.[0] || null;
}

async function fetchCloudflareZoneDetails(zoneId, apiToken) {
  if (!zoneId || !apiToken) return null;
  const payload = await fetchCloudflareApiJson(`https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(String(zoneId).trim())}`, apiToken);
  return payload?.result || null;
}

function isEditableDnsRecordType(value = "") {
  const upper = String(value || "").trim().toUpperCase();
  return upper === "A" || upper === "AAAA" || upper === "CNAME";
}

function normalizeDnsEditModeValue(value = "") {
  return String(value || "").trim().toLowerCase() === "a" ? "a" : "cname";
}

function getDnsContentValidationError(type, content, options = {}) {
  const nextType = String(type || "").trim().toUpperCase();
  const nextContent = String(content || "").trim();
  const allowCname = options.allowCname !== false;
  if (!isEditableDnsRecordType(nextType)) return "Type 仅允许 A / AAAA / CNAME";
  if (!allowCname && nextType === "CNAME") return "A 模式仅允许 A / AAAA";
  if (!nextContent) return "Content 不能为空";
  if (nextType === "A" && !isValidIpv4Address(nextContent)) return "A 记录 Content 必须是合法 IPv4 地址";
  if (nextType === "AAAA" && !isValidIpv6Address(nextContent)) return "AAAA 记录 Content 必须是合法 IPv6 地址";
  if (nextType === "CNAME") {
    if (/\s/.test(nextContent)) return "CNAME 记录 Content 不能包含空格";
    if (nextContent.length > 255) return "CNAME 记录 Content 过长";
  }
  return "";
}

function normalizeDnsFallbackCnameConfigValue(value = "") {
  const text = String(value || "").trim();
  if (!text) return "";
  return getDnsContentValidationError("CNAME", text) ? "" : text;
}

function normalizeEditableDnsRecord(record = {}) {
  return {
    id: String(record?.id || "").trim(),
    type: String(record?.type || "").trim().toUpperCase(),
    name: normalizeHostnameText(record?.name),
    content: String(record?.content || "").trim(),
    ttl: Number(record?.ttl) || 1,
    proxied: record?.proxied === true,
    comment: typeof record?.comment === "string" ? record.comment : undefined,
    tags: Array.isArray(record?.tags) ? record.tags.map(tag => String(tag)) : undefined
  };
}

async function listCloudflareDnsRecords(zoneId, apiToken) {
  const records = [];
  let page = 1;
  let totalPages = 1;
  const perPage = 100;
  do {
    const url = `https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(zoneId)}/dns_records?page=${page}&per_page=${perPage}`;
    const payload = await fetchCloudflareApiJson(url, apiToken);
    if (Array.isArray(payload?.result)) {
      records.push(...payload.result.map(item => normalizeEditableDnsRecord(item)).filter(item => item.id && item.name));
    }
    totalPages = Number(payload?.result_info?.total_pages || payload?.result_info?.totalPages || 1);
    page += 1;
  } while (page <= totalPages && page <= 20);
  return records;
}

function buildCloudflareDnsRecordBody(baseRecord = {}, options = {}) {
  const type = String(options.type || baseRecord?.type || "A").trim().toUpperCase();
  const host = normalizeHostnameText(options.host || baseRecord?.name);
  const content = String(options.content || "").trim();
  const body = {
    type,
    name: host,
    content,
    ttl: Number(baseRecord?.ttl) || 1,
    proxied: baseRecord?.proxied === true
  };
  if (typeof baseRecord?.comment === "string") body.comment = baseRecord.comment;
  if (Array.isArray(baseRecord?.tags)) body.tags = baseRecord.tags.map(tag => String(tag));
  return body;
}

async function resolveCloudflareWorkerServices({ cfAccountId, cfZoneId, cfApiToken }) {
  const serviceNames = new Set();
  const pushName = (rawName) => {
    const name = String(rawName || "").trim();
    if (!name) return;
    serviceNames.add(name);
  };

  if (cfAccountId && cfZoneId) {
    try {
      const url = `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(String(cfAccountId).trim())}/workers/domains?zone_id=${encodeURIComponent(String(cfZoneId).trim())}`;
      const payload = await fetchCloudflareApiJson(url, cfApiToken);
      for (const item of payload?.result || []) {
        pushName(item?.service || item?.script || item?.name);
      }
    } catch (e) {
      console.log("CF Workers domains service lookup failed", e);
    }
  }

  if (cfZoneId) {
    try {
      let page = 1;
      let totalPages = 1;
      do {
        const url = `https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(String(cfZoneId).trim())}/workers/routes?page=${page}&per_page=100`;
        const payload = await fetchCloudflareApiJson(url, cfApiToken);
        totalPages = Number(payload?.result_info?.total_pages || payload?.result_info?.totalPages || 1);
        for (const item of payload?.result || []) {
          pushName(item?.script || item?.service);
        }
        page += 1;
      } while (page <= totalPages && page <= 5);
    } catch (e) {
      console.log("CF Workers routes service lookup failed", e);
    }
  }

  return [...serviceNames];
}

async function fetchCloudflareWorkerUsageMetrics({ cfAccountId, cfZoneId, cfApiToken, startIso, endIso }) {
  if (!cfAccountId || !cfApiToken) return null;
  const serviceNames = await resolveCloudflareWorkerServices({ cfAccountId, cfZoneId, cfApiToken });
  if (!serviceNames.length) return null;

  const query = `
  query {
    viewer {
      accounts(filter: { accountTag: ${toGraphQLString(cfAccountId)} }) {
        workersInvocationsAdaptive(limit: 10000, filter: { datetime_geq: ${toGraphQLString(startIso)}, datetime_leq: ${toGraphQLString(endIso)}, scriptName_in: ${toGraphQLStringArray(serviceNames)} }) {
          dimensions { datetime scriptName status }
          sum { requests }
        }
      }
    }
  }`;

  const accountData = await fetchCloudflareGraphQLAccount(cfAccountId, cfApiToken, query);
  const records = Array.isArray(accountData?.workersInvocationsAdaptive) ? accountData.workersInvocationsAdaptive : [];
  const hourlySeries = Array.from({ length: 24 }, (_, hour) => ({ label: String(hour).padStart(2, "0") + ":00", total: 0 }));

  let totalRequests = 0;
  for (const item of records) {
    const req = Number(item?.sum?.requests) || 0;
    totalRequests += req;

    const dtRaw = item?.dimensions?.datetime;
    if (!dtRaw) continue;
    const dt = new Date(dtRaw);
    if (Number.isNaN(dt.getTime())) continue;
    const hour = (dt.getUTCHours() + 8) % 24;
    if (hourlySeries[hour]) hourlySeries[hour].total += req;
  }

  return { totalRequests, hourlySeries, serviceNames };
}

async function resolveCloudflareBoundHostname({ cfAccountId, cfZoneId, cfApiToken, zoneNameFallback = "" }) {
  const candidates = [];
  const pushCandidate = (rawHostname, options = {}) => {
    const parsed = parseHostnameCandidate(rawHostname);
    if (!parsed) return;
    const wildcard = options.wildcard === true || parsed.wildcard === true;
    candidates.push({
      hostname: parsed.hostname,
      path: String(options.path || ""),
      wildcard,
      score: scoreHostnameCandidate(parsed.hostname, { wildcard, path: options.path || "" })
    });
  };

  if (cfAccountId && cfZoneId) {
    try {
      const url = `https://api.cloudflare.com/client/v4/accounts/${encodeURIComponent(String(cfAccountId).trim())}/workers/domains?zone_id=${encodeURIComponent(String(cfZoneId).trim())}`;
      const payload = await fetchCloudflareApiJson(url, cfApiToken);
      for (const item of payload?.result || []) {
        pushCandidate(item?.hostname);
      }
    } catch (e) {
      console.log("CF Workers domains lookup failed, will try routes", e);
    }
  }

  if (!candidates.length && cfZoneId) {
    try {
      let page = 1;
      let totalPages = 1;
      do {
        const url = `https://api.cloudflare.com/client/v4/zones/${encodeURIComponent(String(cfZoneId).trim())}/workers/routes?page=${page}&per_page=100`;
        const payload = await fetchCloudflareApiJson(url, cfApiToken);
        totalPages = Number(payload?.result_info?.total_pages || payload?.result_info?.totalPages || 1);
        for (const item of payload?.result || []) {
          const info = extractRouteHostnameInfo(item?.pattern);
          if (!info) continue;
          pushCandidate(info.hostname, { wildcard: info.wildcard, path: info.path });
        }
        page += 1;
      } while (page <= totalPages && page <= 5);
    } catch (e) {
      console.log("CF Workers routes lookup failed", e);
    }
  }

  if (candidates.length) {
    candidates.sort((a, b) => (b.score - a.score) || (a.hostname.length - b.hostname.length) || a.hostname.localeCompare(b.hostname));
    return candidates[0].hostname;
  }

  return zoneNameFallback || "未知域名 (请配置 CF 联动)";
}

function sanitizeRuntimeConfig(input = {}) {
  const rawConfig = input && typeof input === "object" && !Array.isArray(input) ? input : {};
  const sanitized = sanitizeConfigWithRules({
    ...rawConfig,
    protocolStrategy: hasOwnConfigKey(rawConfig, "protocolStrategy")
      ? Reflect.get(rawConfig, "protocolStrategy")
      : resolveProtocolStrategyFromLegacyConfig(rawConfig)
  }, CONFIG_SANITIZE_RULES, { normalizeNodeNameList });
  for (const legacyKey of [...CONFIG_LEGACY_LOG_INCLUDE_FIELDS, ...CONFIG_RETIRED_FIELD_KEYS]) {
    delete sanitized[legacyKey];
  }
  sanitized.prewarmDepth = normalizePrewarmDepth(sanitized.prewarmDepth);
  sanitized.dnsDefaultFallbackCname = normalizeDnsFallbackCnameConfigValue(sanitized.dnsDefaultFallbackCname);
  sanitized.settingsExperienceMode = String(sanitized.settingsExperienceMode || '').trim().toLowerCase() === 'expert' ? 'expert' : 'novice';
  sanitized.logSearchMode = normalizeLogSearchMode(sanitized.logSearchMode);
  sanitized.routingDecisionMode = normalizeRoutingDecisionMode(sanitized.routingDecisionMode);
  sanitized.protocolStrategy = normalizeProtocolStrategy(sanitized.protocolStrategy);
  sanitized.defaultRealClientIpMode = normalizeDefaultRealClientIpMode(sanitized.defaultRealClientIpMode);
  sanitized.defaultMediaAuthMode = normalizeDefaultMediaAuthMode(sanitized.defaultMediaAuthMode);
  sanitized.scheduleUtcOffsetMinutes = normalizeScheduleUtcOffsetMinutes(sanitized.scheduleUtcOffsetMinutes);
  sanitized.dnsAutoUploadTime = normalizeScheduleClockTime(sanitized.dnsAutoUploadTime, Config.Defaults.DnsAutoUploadTime);
  sanitized.tgDailyReportTime = normalizeScheduleClockTime(sanitized.tgDailyReportTime, Config.Defaults.TgDailyReportTime);
  sanitized.dnsAutoUploadCountryCodes = normalizeDnsAutoUploadCountryCodes(sanitized.dnsAutoUploadCountryCodes);
  sanitized.dnsAutoUploadRecordTypes = normalizeDnsAutoUploadRecordTypes(sanitized.dnsAutoUploadRecordTypes);
  return sanitized;
}

function normalizeDistinctConfigKeyList(values = []) {
  const list = Array.isArray(values) ? values : [values];
  const result = [];
  const seen = new Set();
  for (const value of list) {
    const key = String(value || "").trim();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    result.push(key);
  }
  return result;
}

function collectLegacyRuntimeConfigState(input = {}) {
  const rawConfig = input && typeof input === "object" && !Array.isArray(input) ? input : {};
  const legacyKeysPresent = [];
  for (const legacyKey of CONFIG_LEGACY_MIGRATION_SOURCE_FIELDS) {
    if (!Object.prototype.hasOwnProperty.call(rawConfig, legacyKey)) continue;
    legacyKeysPresent.push(legacyKey);
  }
  const migratedConfigKeys = [];
  const migratedKeyMap = {};
  const pushMigratedKey = (sourceKey, targetKey) => {
    const normalizedSource = String(sourceKey || "").trim();
    const normalizedTarget = String(targetKey || "").trim();
    if (!normalizedSource || !normalizedTarget) return;
    migratedConfigKeys.push(normalizedTarget);
    if (!migratedKeyMap[normalizedSource]) migratedKeyMap[normalizedSource] = [];
    migratedKeyMap[normalizedSource].push(normalizedTarget);
  };

  if (!Object.prototype.hasOwnProperty.call(rawConfig, "sourceDirectNodes")) {
    for (const sourceKey of CONFIG_SOURCE_DIRECT_NODE_ALIAS_FIELDS) {
      if (!Object.prototype.hasOwnProperty.call(rawConfig, sourceKey)) continue;
      if (rawConfig[sourceKey] === undefined || rawConfig[sourceKey] === null) continue;
      pushMigratedKey(sourceKey, "sourceDirectNodes");
      break;
    }
  }

  if (!Object.prototype.hasOwnProperty.call(rawConfig, "logWriteClientIp") && Reflect.get(rawConfig, "logIncludeClientIp") !== undefined) {
    pushMigratedKey("logIncludeClientIp", "logWriteClientIp");
  }
  if (!Object.prototype.hasOwnProperty.call(rawConfig, "logDisplayClientIp") && Reflect.get(rawConfig, "logIncludeClientIp") !== undefined) {
    pushMigratedKey("logIncludeClientIp", "logDisplayClientIp");
  }
  if (!Object.prototype.hasOwnProperty.call(rawConfig, "logWriteColo") && Reflect.get(rawConfig, "logIncludeColo") !== undefined) {
    pushMigratedKey("logIncludeColo", "logWriteColo");
  }
  if (!Object.prototype.hasOwnProperty.call(rawConfig, "logDisplayColo") && Reflect.get(rawConfig, "logIncludeColo") !== undefined) {
    pushMigratedKey("logIncludeColo", "logDisplayColo");
  }
  if (!Object.prototype.hasOwnProperty.call(rawConfig, "logWriteUa") && Reflect.get(rawConfig, "logIncludeUa") !== undefined) {
    pushMigratedKey("logIncludeUa", "logWriteUa");
  }
  if (!Object.prototype.hasOwnProperty.call(rawConfig, "logDisplayUa") && Reflect.get(rawConfig, "logIncludeUa") !== undefined) {
    pushMigratedKey("logIncludeUa", "logDisplayUa");
  }
  if (!Object.prototype.hasOwnProperty.call(rawConfig, "protocolStrategy")) {
    for (const sourceKey of CONFIG_PROTOCOL_STRATEGY_LEGACY_FIELDS) {
      if (!Object.prototype.hasOwnProperty.call(rawConfig, sourceKey)) continue;
      pushMigratedKey(sourceKey, "protocolStrategy");
    }
  }

  return {
    legacyKeysPresent: normalizeDistinctConfigKeyList(legacyKeysPresent),
    deletedLegacyFieldCount: normalizeDistinctConfigKeyList(legacyKeysPresent).length,
    migratedConfigKeys: normalizeDistinctConfigKeyList(migratedConfigKeys),
    migratedKeyMap: Object.fromEntries(Object.entries(migratedKeyMap).map(([key, targets]) => [key, normalizeDistinctConfigKeyList(targets)]))
  };
}

function migrateLegacyRuntimeConfig(input = {}) {
  const migrationState = collectLegacyRuntimeConfigState(input);
  return {
    cleanedConfig: sanitizeRuntimeConfig(input),
    ...migrationState
  };
}

function normalizeConfigSnapshotChangedKeys(changedKeys = []) {
  const normalizedChangedKeys = [];
  const removedLegacyKeys = [];
  const seen = new Set();
  for (const rawKey of Array.isArray(changedKeys) ? changedKeys : []) {
    const key = String(rawKey || "").trim();
    if (!key) continue;
    const mappedKeys = CONFIG_SNAPSHOT_CHANGED_KEY_MIGRATIONS[key];
    if (Array.isArray(mappedKeys) && mappedKeys.length) {
      removedLegacyKeys.push(key);
      for (const mappedKey of mappedKeys) {
        if (!mappedKey || seen.has(mappedKey)) continue;
        seen.add(mappedKey);
        normalizedChangedKeys.push(mappedKey);
      }
      continue;
    }
    if (CONFIG_LEGACY_SNAPSHOT_DROP_KEY_SET.has(key)) {
      removedLegacyKeys.push(key);
      continue;
    }
    if (seen.has(key)) continue;
    seen.add(key);
    normalizedChangedKeys.push(key);
  }
  return {
    changedKeys: normalizedChangedKeys,
    removedLegacyKeys: normalizeDistinctConfigKeyList(removedLegacyKeys)
  };
}

function rewriteConfigSnapshotToCurrentSchema(snapshot) {
  if (!snapshot || typeof snapshot !== "object" || Array.isArray(snapshot)) {
    return {
      snapshot,
      rewritten: false,
      deletedLegacyFieldCount: 0,
      migratedConfigKeys: []
    };
  }
  const snapshotConfig = snapshot.config && typeof snapshot.config === "object" && !Array.isArray(snapshot.config) ? snapshot.config : {};
  const configMigration = migrateLegacyRuntimeConfig(snapshotConfig);
  const changedKeyMigration = normalizeConfigSnapshotChangedKeys(snapshot.changedKeys);
  const nextSnapshot = {
    ...snapshot,
    changedKeys: changedKeyMigration.changedKeys,
    changeCount: changedKeyMigration.changedKeys.length,
    config: configMigration.cleanedConfig
  };
  const previousChangedKeys = Array.isArray(snapshot.changedKeys) ? snapshot.changedKeys : [];
  const previousChangeCount = Number(snapshot.changeCount) || previousChangedKeys.length || 0;
  const rewritten = serializeConfigValue(snapshot.config || {}) !== serializeConfigValue(nextSnapshot.config)
    || serializeConfigValue(previousChangedKeys) !== serializeConfigValue(nextSnapshot.changedKeys)
    || previousChangeCount !== nextSnapshot.changeCount;
  return {
    snapshot: nextSnapshot,
    rewritten,
    deletedLegacyFieldCount: configMigration.deletedLegacyFieldCount + changedKeyMigration.removedLegacyKeys.length,
    migratedConfigKeys: configMigration.migratedConfigKeys
  };
}

function classifyLogResourceScope(requestPath = "", category = "") {
  const path = String(requestPath || "").trim().toLowerCase();
  const normalizedCategory = String(category || "").trim().toLowerCase();
  if (normalizedCategory === "image" || path.includes("/images/") || path.includes("/emby/covers/") || /\.(jpe?g|png|webp|gif)(?:$|[?#])/.test(path)) {
    return "image_poster";
  }
  if (path.includes("/sessions/playing") || path.includes("/playbackinfo")) return "playback_info";
  if (path.includes("/users/authenticate")) return "auth";
  if (path.includes("/items/") || path.includes("/shows/") || path.includes("/movies/") || path.includes("/users/")) {
    return "media_metadata";
  }
  return normalizedCategory || "api";
}

function isPlaybackInfoLogRequest(requestPath = "", category = "") {
  return classifyLogResourceScope(requestPath, category) === "playback_info";
}

function isVideoStreamLogRequest(requestPath = "", category = "") {
  const path = String(requestPath || "").trim().toLowerCase();
  const normalizedCategory = String(category || "").trim().toLowerCase();
  if (normalizedCategory === "stream" || normalizedCategory === "segment" || normalizedCategory === "manifest") return true;
  return /\/stream(?:$|[/?])/.test(path)
    || path.includes("/master.m3u8")
    || /\/videos\/[^/]+\/(?:original|download|file)(?:$|[/?])/.test(path)
    || /\/items\/[^/]+\/download(?:$|[/?])/.test(path)
    || path.includes("static=true")
    || path.includes("download=true");
}

function serializeConfigValue(value) {
  if (Array.isArray(value)) return JSON.stringify(value);
  if (isPlainObject(value)) return JSON.stringify(value);
  if (value === undefined) return "";
  return JSON.stringify(value);
}

function buildRevisionValue(hash = "", updatedAt = "") {
  const safeHash = String(hash || "").trim() || "empty";
  const safeUpdatedAt = String(updatedAt || "").trim() || new Date().toISOString();
  return `${safeUpdatedAt}.${safeHash}`;
}

function buildHashedMetaPayload(payload, extra = {}) {
  const serialized = serializeConfigValue(payload);
  const hash = hashStableText(serialized);
  const updatedAt = String(extra.updatedAt || "").trim() || new Date().toISOString();
  return {
    ...extra,
    hash,
    updatedAt,
    revision: buildRevisionValue(hash, updatedAt)
  };
}

function getConfigDiffEntries(prevConfig = {}, nextConfig = {}) {
  const prev = sanitizeRuntimeConfig(prevConfig);
  const next = sanitizeRuntimeConfig(nextConfig);
  const keys = [...new Set([...Object.keys(prev), ...Object.keys(next)])].sort();
  const entries = [];
  for (const key of keys) {
    if (serializeConfigValue(prev[key]) === serializeConfigValue(next[key])) continue;
    entries.push({
      key,
      previousValue: prev[key],
      nextValue: next[key]
    });
  }
  return entries;
}

function classifyCloudflareAnalyticsError(message, options = {}) {
  const raw = String(message || "").trim();
  const lower = raw.toLowerCase();
  const zoneId = String(options.zoneId || "").trim();
  const result = {
    status: "CF 查询失败",
    hint: "Cloudflare 查询失败，请检查 Zone ID、API 令牌与资源范围",
    detail: raw || (zoneId ? `当前查询的 Zone ID: ${zoneId}` : "")
  };
  if (!raw) return result;
  if (lower.includes("unknown field") || lower.includes("unknown enum") || lower.includes("error parsing args")) {
    return {
      status: "Schema 不兼容",
      hint: "当前账号可用的 GraphQL schema 与脚本查询字段不一致",
      detail: raw
    };
  }
  if (lower.includes("cf_graphql_http_429") || lower.includes("rate limit") || lower.includes("too many requests")) {
    return {
      status: "请求过于频繁",
      hint: "Cloudflare GraphQL 已限流，请稍后再试",
      detail: raw
    };
  }
  if (lower.includes("invalid token") || lower.includes("authentication") || lower.includes("cf_graphql_http_401")) {
    return {
      status: "令牌无效",
      hint: "Cloudflare API 令牌无效，或未启用 GraphQL Analytics 访问",
      detail: raw
    };
  }
  if (lower.includes("not authorized") || lower.includes("permission") || lower.includes("forbidden") || lower.includes("unauthorized") || lower.includes("cf_graphql_http_403")) {
    return {
      status: "权限或范围不匹配",
      hint: "令牌权限不足，或 Account / Zone Resources 未覆盖当前查询",
      detail: raw + (zoneId ? ` | Zone ID: ${zoneId}` : "")
    };
  }
  if (lower.includes("zone") && (lower.includes("not found") || lower.includes("invalid") || lower.includes("unknown"))) {
    return {
      status: "Zone ID 无效",
      hint: "Zone ID 无效，或当前令牌无法访问这个 Zone",
      detail: raw + (zoneId ? ` | Zone ID: ${zoneId}` : "")
    };
  }
  if (lower.includes("cf_graphql_http_400")) {
    return {
      status: "请求参数无效",
      hint: "GraphQL 请求参数无效，请检查 Zone ID 与筛选条件",
      detail: raw + (zoneId ? ` | Zone ID: ${zoneId}` : "")
    };
  }
  return result;
}

async function getRuntimeConfig(env) {
  const kv = Auth.getKV(env);
  if (!kv) return {};
  const now = nowMs();
  const cacheNamespace = String(
    env?.__CONFIG_CACHE_NAMESPACE
    || env?.__WORKER_CACHE_SCOPE
    || (env?.ENI_KV ? "ENI_KV" : "")
    || (env?.KV ? "KV" : "")
    || (env?.EMBY_KV ? "EMBY_KV" : "")
    || (env?.EMBY_PROXY ? "EMBY_PROXY" : "")
    || "default"
  );
  if (GLOBALS.ConfigCache && GLOBALS.ConfigCache.exp > now && GLOBALS.ConfigCache.data && GLOBALS.ConfigCache.namespace === cacheNamespace) return GLOBALS.ConfigCache.data;
  let config = {};
  try { config = sanitizeRuntimeConfig(await kv.get(Database.CONFIG_KEY, { type: "json" }) || {}); } catch {}
  GLOBALS.ConfigCache = { data: config, exp: now + 60000, namespace: cacheNamespace };
  return config;
}

function parseCookieHeader(cookieHeader) {
  const map = new Map();
  if (!cookieHeader || typeof cookieHeader !== "string") return map;
  for (const rawPart of cookieHeader.split(";")) {
    const part = rawPart.trim();
    if (!part) continue;
    const eqIndex = part.indexOf("=");
    const key = (eqIndex === -1 ? part : part.slice(0, eqIndex)).trim();
    const value = eqIndex === -1 ? "" : part.slice(eqIndex + 1).trim();
    if (!key) continue;
    map.set(key, value);
  }
  return map;
}

function serializeCookieMap(cookieMap) {
  const parts = [];
  for (const [key, value] of cookieMap.entries()) {
    parts.push(value === "" ? key : `${key}=${value}`);
  }
  return parts.join("; ");
}

function mergeAndSanitizeCookieHeaders(baseCookieHeader, extraCookieHeader, blockedCookieNames = ["auth_token"]) {
  const blocked = new Set(blockedCookieNames.map(name => String(name || "").trim().toLowerCase()).filter(Boolean));
  const merged = parseCookieHeader(baseCookieHeader);
  for (const key of [...merged.keys()]) {
    if (blocked.has(String(key).trim().toLowerCase())) merged.delete(key);
  }
  const extra = parseCookieHeader(extraCookieHeader);
  for (const [key, value] of extra.entries()) {
    if (blocked.has(String(key).trim().toLowerCase())) continue;
    merged.set(key, value);
  }
  const result = serializeCookieMap(merged);
  return result || null;
}

function jsonHeaders(extra = {}) {
  return { ...GLOBALS.SecurityHeaders, ...corsHeaders, "Content-Type": "application/json; charset=utf-8", "Cache-Control": "no-store, max-age=0", ...extra };
}

function jsonResponse(payload, status = 200, extraHeaders = {}) {
  return new Response(JSON.stringify(payload), { status, headers: jsonHeaders(extraHeaders) });
}

function jsonError(code, message, status = 400, details = null, extraHeaders = {}) {
  const body = { ok: false, error: { code, message } };
  if (details !== null && details !== undefined) body.error.details = details;
  return jsonResponse(body, status, extraHeaders);
}

function isPlainObject(value) {
  return !!value && typeof value === "object" && !Array.isArray(value);
}

function mergeStatusPatch(base, patch) {
  const source = isPlainObject(base) ? base : {};
  const delta = isPlainObject(patch) ? patch : {};
  const merged = { ...source };
  for (const [key, value] of Object.entries(delta)) {
    if (value === undefined) continue;
    if (isPlainObject(value) && isPlainObject(source[key])) merged[key] = mergeStatusPatch(source[key], value);
    else if (isPlainObject(value)) merged[key] = mergeStatusPatch({}, value);
    else merged[key] = value;
  }
  return merged;
}

async function normalizeJsonApiResponse(response) {
  const headers = new Headers(response.headers || {});
  headers.set("Content-Type", "application/json; charset=utf-8");
  headers.set("Cache-Control", "no-store, max-age=0");
  Object.entries(corsHeaders).forEach(([k, v]) => headers.set(k, v));
  applySecurityHeaders(headers);
  if (response.ok) return new Response(response.body, { status: response.status, headers });
  let payload = null, fallbackText = "";
  try { payload = await response.clone().json(); } catch { fallbackText = await response.text().catch(() => ""); }
  const code = payload?.error?.code || (typeof payload?.error === "string" ? payload.error.toUpperCase() : `HTTP_${response.status}`);
  const message = payload?.error?.message || payload?.message || (typeof payload?.error === "string" ? payload.error : fallbackText || response.statusText || "request_failed");
  const details = payload?.error?.details ?? payload?.details ?? null;
  return jsonError(code, message, response.status || 500, details);
}

const nowMs = () => Date.now();
const sleepMs = (ms) => new Promise(resolve => setTimeout(resolve, Math.max(0, Number(ms) || 0)));

function isAbortLikeError(error) {
  if (!error) return false;
  if (error.name === "AbortError") return true;
  return String(error.message || "").toLowerCase().includes("abort");
}

function createLifecycleAbortError(reason, detail = "") {
  const normalizedReason = String(reason || "request_aborted").trim() || "request_aborted";
  /** @type {AppError} */
  const error = new Error(detail ? `${normalizedReason}_${detail}` : normalizedReason);
  if (normalizedReason === "client_aborted") error.code = "CLIENT_ABORTED";
  else if (normalizedReason === "downstream_cancelled") error.code = "DOWNSTREAM_CANCELLED";
  else if (normalizedReason === "stream_idle_timeout") error.code = "STREAM_IDLE_TIMEOUT";
  else error.code = "REQUEST_ABORTED";
  return error;
}

function createProxyRequestLifecycle(requestSignal) {
  const controller = new AbortController();
  let abortReason = "";
  let requestAbortCleanup = null;
  let activeFetchController = null;
  let activeFetchCleanup = null;
  const abortListeners = new Set();

  const notifyAbortListeners = (reason) => {
    if (!abortListeners.size) return;
    for (const listener of [...abortListeners]) {
      try { listener(reason); } catch {}
    }
  };

  const abort = (reason = "request_aborted") => {
    const normalizedReason = String(reason || "request_aborted").trim() || "request_aborted";
    if (!abortReason) abortReason = normalizedReason;
    if (activeFetchController && !activeFetchController.signal.aborted) {
      try { activeFetchController.abort(abortReason); } catch {}
    }
    if (!controller.signal.aborted) {
      try { controller.abort(abortReason); } catch {}
    }
    notifyAbortListeners(abortReason);
  };

  if (requestSignal && typeof requestSignal.addEventListener === "function") {
    const onRequestAbort = () => abort("client_aborted");
    if (requestSignal.aborted) onRequestAbort();
    else {
      requestSignal.addEventListener("abort", onRequestAbort, { once: true });
      requestAbortCleanup = () => requestSignal.removeEventListener("abort", onRequestAbort);
    }
  }

  return {
    signal: controller.signal,
    abort,
    isAborted() {
      return controller.signal.aborted === true || !!abortReason;
    },
    getAbortReason() {
      return abortReason;
    },
    onAbort(listener) {
      if (typeof listener !== "function") return () => {};
      if (abortReason || controller.signal.aborted) {
        try { listener(abortReason || "request_aborted"); } catch {}
        return () => {};
      }
      abortListeners.add(listener);
      return () => abortListeners.delete(listener);
    },
    setActiveFetchController(fetchController) {
      if (activeFetchCleanup) {
        activeFetchCleanup();
        activeFetchCleanup = null;
      }
      activeFetchController = fetchController || null;
      if (!fetchController) return () => {};

      const relayAbort = () => {
        try { fetchController.abort(abortReason || "request_aborted"); } catch {}
      };

      if (abortReason || controller.signal.aborted) relayAbort();
      else controller.signal.addEventListener("abort", relayAbort, { once: true });

      activeFetchCleanup = () => {
        controller.signal.removeEventListener("abort", relayAbort);
        if (activeFetchController === fetchController) activeFetchController = null;
      };

      return () => {
        if (!activeFetchCleanup) return;
        const cleanup = activeFetchCleanup;
        activeFetchCleanup = null;
        cleanup();
      };
    },
    dispose() {
      if (requestAbortCleanup) {
        requestAbortCleanup();
        requestAbortCleanup = null;
      }
      if (activeFetchCleanup) {
        const cleanup = activeFetchCleanup;
        activeFetchCleanup = null;
        cleanup();
      } else {
        activeFetchController = null;
      }
      abortListeners.clear();
    }
  };
}

function setBoundedMapEntry(map, key, value, maxSize) {
  if (map.has(key)) map.delete(key);
  map.set(key, value);
  const limit = Math.floor(Number(maxSize));
  if (!Number.isFinite(limit) || limit < 1) return;
  while (map.size > limit) {
    const oldestKey = map.keys().next().value;
    if (oldestKey === undefined) break;
    map.delete(oldestKey);
  }
}

function touchMapEntry(map, key) {
  if (!map.has(key)) return undefined;
  const value = map.get(key);
  map.delete(key);
  map.set(key, value);
  return value;
}

function clampIntegerConfig(value, fallback, min, max) {
  let num;
  if (typeof value === "number") num = value;
  else if (typeof value === "string") {
    const normalized = value.trim();
    if (!/^-?\d+$/.test(normalized)) return fallback;
    num = Number(normalized);
  } else {
    return fallback;
  }
  if (!Number.isFinite(num)) return fallback;
  return Math.min(max, Math.max(min, Math.floor(num)));
}

function clampNumberConfig(value, fallback, min, max) {
  const num = Number(value);
  if (!Number.isFinite(num)) return fallback;
  return Math.min(max, Math.max(min, num));
}

